 26→export function Digest() {
 27→  const [loading, setLoading] = useState<"idle" | "loading" | "success">(
 28→    "idle"
 29→  );
 30→  const [error, setError] = useState<SignUpError | null>(null);
 31→
 32→  const handleSignUp = async (
 33→    event: React.FormEvent<HTMLFormElement>
 34→  ): Promise<void> => {
 35→    event.preventDefault();
 36→    const form = event.target as HTMLFormElement;
 37→    const emailInput = form.elements.namedItem("email") as HTMLInputElement;
 38→    setLoading("loading");
 39→    try {
 40→      const res = await fetch("/api/confirm", {
 41→        method: "POST",
 42→        headers: {
 43→          "Content-Type": "application/json",
 44→        },
 45→        body: JSON.stringify({
 46→          email: emailInput.value,
 47→        }),
 48→      });
 49→      const data: SignUpResponse = await res.json();
 50→      if ("error" in data) {
 51→        setError(data);
 52→        setLoading("idle");
 53→      } else {
 54→        setLoading("success");
 55→        form.reset();
 56→      }
 57→    } catch (_error) {
 58→      setError({
 59→        error: {
 60→          message: "A network error occurred. Please try again.",
 61→          name: "NetworkError",
 62→        },
 63→      });
 64→      setLoading("idle");
 65→    }
 66→  };
 67→
 68→  return (
 69→    <section aria-label="Digest sign-up" id="digest">
 70→      <Container className="relative py-20" size="xs">
 71→        <form className="lg:pl-16" onSubmit={handleSignUp}>
 72→          <h3 className="font-medium text-base text-gray-800 tracking-tight">
 73→            Be the first to collect hazelnuts!
 74→          </h3>
 75→          <div className="mt-4 sm:relative sm:flex sm:items-center sm:px-1 sm:py-0.5">
 76→            <div className="relative sm:static sm:flex-auto">
 77→              <input
 78→                aria-label="Email address"
 79→                className="peer relative z-10 w-full appearance-none rounded-md bg-transparent px-4 py-2 text-base text-gray-900 placeholder:text-gray-500 focus:outline-none sm:py-3"
 80→                id="email"
 81→                name="email"
 82→                placeholder="Email address"
 83→                required
 84→                type="email"
 85→              />
 86→              <div className="absolute inset-0 rounded-md border border-gray-400 peer-focus:border-blue-500 peer-focus:bg-white/5 peer-focus:ring-1 peer-focus:ring-blue-500 sm:rounded-lg" />
 87→            </div>
 88→            <button
 89→              className="mt-4 inline-flex w-full items-center justify-center overflow-hidden rounded-md border border-transparent bg-white px-4 py-2 font-semibold text-base text-ht-blue-700 tracking-tight shadow-[0_0_0.2em_0em_rgba(56,189,248,0.2)] ring-1 ring-black/10 hover:text-ht-blue-800 hover:shadow-[0_0_0.5em_0em_rgba(56,189,248,0.4)] focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 active:bg-blue-50 disabled:cursor-not-allowed disabled:opacity-70 sm:relative sm:z-10 sm:mt-0 sm:w-48 sm:flex-none"
 90→              disabled={loading !== "idle"}
 91→              type="submit"
 92→            >
 93→              <AnimatePresence initial={false} mode="popLayout">
 94→                <motion.span
 95→                  animate={{ opacity: 1, y: 0 }}
 96→                  exit={{ opacity: 0, y: 25 }}
 97→                  initial={{ opacity: 0, y: -25 }}
 98→                  key={loading}
 99→                  transition={{ type: "spring", duration: 0.3, bounce: 0 }}
100→                >
101→                  {buttonCopy[loading]}
102→                </motion.span>
103→              </AnimatePresence>
104→            </button>
105→          </div>
106→        </form>
107→        <div className="mt-4">
108→          {loading === "success" && (
109→            <p className="font-medium text-base text-ht-blue-700">
110→              A confirmation email has been sent to you.
111→            </p>
112→          )}
113→          {error && (
114→            <p className="text-ht-red-700 text-sm">
115→              Error: {error.error.message}
116→            </p>
117→          )}
118→        </div>
119→      </Container>
120→    </section>
121→  );
122→}
