 71→function TestimonialCard({
 72→  name,
 73→  title,
 74→  img,
 75→  children,
 76→  bounds,
 77→  scrollX,
 78→  ...props
 79→}: {
 80→  img: string;
 81→  name: string;
 82→  title: string;
 83→  children: React.ReactNode;
 84→  bounds: RectReadOnly;
 85→  scrollX: MotionValue<number>;
 86→} & HTMLMotionProps<"div">) {
 87→  const ref = useRef<HTMLDivElement | null>(null);
 88→
 89→  const computeOpacity = useCallback(() => {
 90→    const element = ref.current;
 91→    if (!element || bounds.width === 0) {
 92→      return 1;
 93→    }
 94→
 95→    const rect = element.getBoundingClientRect();
 96→
 97→    if (rect.left < bounds.left) {
 98→      const diff = bounds.left - rect.left;
 99→      const percent = diff / rect.width;
100→      return Math.max(MIN_CARD_OPACITY, 1 - percent);
101→    }
102→    if (rect.right > bounds.right) {
103→      const diff = rect.right - bounds.right;
104→      const percent = diff / rect.width;
105→      return Math.max(MIN_CARD_OPACITY, 1 - percent);
106→    }
107→    return 1;
108→  }, [bounds.width, bounds.left, bounds.right]);
109→
110→  const opacity = useSpring(computeOpacity(), {
111→    stiffness: SPRING_STIFFNESS,
112→    damping: SPRING_DAMPING,
113→  });
114→
115→  useLayoutEffect(() => {
116→    opacity.set(computeOpacity());
117→  }, [computeOpacity, opacity]);
118→
119→  useMotionValueEvent(scrollX, "change", () => {
120→    opacity.set(computeOpacity());
121→  });
122→
123→  return (
124→    <motion.div
125→      ref={ref}
126→      style={{ opacity }}
127→      {...props}
128→      className="relative flex aspect-9/16 w-72 shrink-0 snap-start scroll-ml-(--scroll-padding) flex-col justify-end overflow-hidden rounded-3xl sm:aspect-3/4 sm:w-96"
129→    >
130→      <Image
131→        alt=""
132→        className="absolute inset-x-0 top-0 aspect-square w-full object-cover"
133→        height={384}
134→        src={img}
135→        width={384}
136→      />
137→      <div
138→        aria-hidden="true"
139→        className="absolute inset-0 inset-ring inset-ring-gray-950/10 rounded-3xl bg-linear-to-t from-[calc(7/16*100%)] from-black sm:from-25%"
140→      />
141→      <figure className="relative p-10">
142→        <blockquote>
143→          <p className="relative text-white text-xl/7">{children}</p>
144→        </blockquote>
145→        <figcaption className="mt-6 border-white/20 border-t pt-6">
146→          <p className="font-medium text-sm/6 text-white">{name}</p>
147→          <p className="font-medium text-sm/6">
148→            <span className="bg-linear-to-r from-28% from-[#bef4ff] via-70% via-[#eecf87] to-[#c2e240] bg-clip-text text-transparent">
149→              {title}
150→            </span>
151→          </p>
152→        </figcaption>
153→      </figure>
154→    </motion.div>
155→  );
156→}
