177→export function Testimonials() {
178→  const scrollRef = useRef<HTMLDivElement | null>(null);
179→  const { scrollX } = useScroll({ container: scrollRef });
180→  const [setReferenceWindowRef, bounds] = useMeasure();
181→  const [activeIndex, setActiveIndex] = useState(0);
182→
183→  useMotionValueEvent(scrollX, "change", (x) => {
184→    startTransition(() => {
185→      const containerWidth = scrollRef.current?.children[0].clientWidth ?? 1;
186→      setActiveIndex(Math.floor(x / containerWidth));
187→    });
188→  });
189→
190→  function scrollTo(index: number) {
191→    const gap = 32;
192→    // biome-ignore lint/style/noNonNullAssertion: ref is always set when scrollTo is called
193→    const width = (scrollRef.current!.children[0] as HTMLElement).offsetWidth;
194→    // biome-ignore lint/style/noNonNullAssertion: ref is always set when scrollTo is called
195→    scrollRef.current!.scrollTo({ left: (width + gap) * index });
196→  }
197→
198→  return (
199→    <div className="overflow-hidden bg-white py-32">
200→      <Container>
201→        <div ref={setReferenceWindowRef}>
202→          <Subheading>What to expect</Subheading>
203→          <Heading as="h3" className="mt-2">
204→            You will{" "}
205→            <span className="inline-block -rotate-1 bg-ht-cyan-400/50 py-3 pr-2 pl-1 text-zinc-900">
206→              not enjoy
207→            </span>{" "}
208→            hasToggle if ...
209→          </Heading>
210→        </div>
211→      </Container>
212→      <div
213→        className={cn([
214→          "mt-16 flex gap-8 px-(--scroll-padding)",
215→          "[scrollbar-width:none] [&::-webkit-scrollbar]:hidden",
216→          "snap-x snap-mandatory overflow-x-auto overscroll-x-contain scroll-smooth",
217→          "[--scroll-padding:max(1.5rem,calc((100vw-42rem)/2))] lg:[--scroll-padding:max(2rem,calc((100vw-80rem)/2))]",
218→        ])}
219→        ref={scrollRef}
220→      >
221→        {testimonials.map(({ img, name, title, quote }, testimonialIndex) => (
222→          <TestimonialCard
223→            bounds={bounds}
224→            img={img}
225→            key={name}
226→            name={name}
227→            onClick={() => scrollTo(testimonialIndex)}
228→            scrollX={scrollX}
229→            title={title}
230→          >
231→            {quote}
232→          </TestimonialCard>
233→        ))}
234→        <div className="w-2xl shrink-0 sm:w-216" />
235→      </div>
236→      <Container className="mt-16">
237→        <div className="flex justify-between">
238→          <CallToAction />
239→          <div className="hidden sm:flex sm:gap-2">
240→            {testimonials.map(({ name }, testimonialIndex) => (
241→              <button
242→                aria-label={`Scroll to testimonial from ${name}`}
243→                className={cn(
244→                  "size-2.5 rounded-full border border-transparent bg-gray-300 transition",
245→                  "hover:bg-gray-400 data-active:bg-gray-400",
246→                  "forced-colors:data-active:bg-[Highlight] forced-colors:focus:outline-offset-4"
247→                )}
248→                data-active={
249→                  activeIndex === testimonialIndex ? true : undefined
250→                }
251→                key={name}
252→                onClick={() => scrollTo(testimonialIndex)}
253→                type="button"
254→              />
255→            ))}
256→          </div>
257→        </div>
258→      </Container>
259→    </div>
260→  );
261→}
