 1→import { createId, database } from "@repo/database";
 2→import { resend } from "@repo/email";
 3→import { ConfirmSubscription } from "@repo/email/templates/confirm-subscription";
 4→import { parseError } from "@repo/observability/error";
 5→import { after, type NextRequest, NextResponse } from "next/server";
 6→import { env } from "@/env";
 7→import { generateToken } from "@/lib/token";
 8→
 9→const TOKEN_EXPIRY_MS = 1000 * 60 * 60 * 24;
10→
11→export async function POST(request: NextRequest) {
12→  try {
13→    const res = await request.json();
14→    const email = res.email;
15→
16→    if (!email || typeof email !== "string" || !email.includes("@")) {
17→      return NextResponse.json(
18→        {
19→          error: {
20→            message: "Invalid email address provided",
21→            name: "ValidationError",
22→          },
23→        },
24→        { status: 400 }
25→      );
26→    }
27→
28→    const { token, hash } = generateToken();
29→
30→    await database.subscriber.updateOne(
31→      { email },
32→      {
33→        $set: {
34→          token: hash,
35→          tokenExpiresAt: new Date(Date.now() + TOKEN_EXPIRY_MS),
36→        },
37→        $setOnInsert: {
38→          _id: createId(),
39→          role: "user",
40→          name: null,
41→          emailVerified: null,
42→          image: null,
43→          createdAt: new Date(),
44→        },
45→      },
46→      { upsert: true }
47→    );
48→
49→    const { error } = await resend.emails.send({
50→      from: env.RESEND_FROM,
51→      to: [email],
52→      subject: "Important: Confirm your subscription",
53→      react: ConfirmSubscription({
54→        token,
55→        baseUrl: new URL(request.url).origin,
56→      }),
57→    });
58→
59→    if (error) {
60→      return NextResponse.json(
61→        {
62→          error: {
63→            message: "Failed to send confirmation email",
64→            name: "EmailError",
65→          },
66→        },
67→        { status: 500 }
68→      );
69→    }
70→
71→    return NextResponse.json({
72→      message: "Confirm your subscription.",
73→    });
74→  } catch (error) {
75→    after(() => parseError(error));
76→    return NextResponse.json(
77→      {
78→        error: { message: "An unexpected error occurred", name: "ServerError" },
79→      },
80→      { status: 500 }
81→    );
82→  }
83→}
