 1→import { database } from "@repo/database";
 2→import { resend } from "@repo/email";
 3→import { parseError } from "@repo/observability/error";
 4→import { after, type NextRequest, NextResponse } from "next/server";
 5→import { env } from "@/env";
 6→import { generateTokenHash } from "@/lib/token";
 7→
 8→export async function GET(request: NextRequest) {
 9→  try {
10→    const { searchParams } = new URL(request.url);
11→    const token = searchParams.get("token");
12→
13→    if (!token) {
14→      return NextResponse.json(
15→        { error: "A valid confirmation link is required" },
16→        { status: 400 }
17→      );
18→    }
19→
20→    const subscriber = await database.subscriber.findOne({
21→      token: generateTokenHash(token),
22→      tokenExpiresAt: { $gte: new Date() },
23→    });
24→
25→    if (!subscriber) {
26→      return NextResponse.json(
27→        { error: "Invalid or expired confirmation link" },
28→        { status: 400 }
29→      );
30→    }
31→
32→    const updatePromise = subscriber.emailVerified
33→      ? Promise.resolve()
34→      : database.subscriber.updateOne(
35→          { _id: subscriber._id },
36→          { $set: { emailVerified: new Date(), tokenExpiresAt: null } }
37→        );
38→
39→    const contactPromise = resend.contacts.create({
40→      email: subscriber.email,
41→      unsubscribed: false,
42→      audienceId: env.RESEND_AUDIENCE_ID,
43→    });
44→
45→    const [, { error }] = await Promise.all([updatePromise, contactPromise]);
46→
47→    if (error) {
48→      after(() => parseError(error));
49→    }
50→
51→    return new Response(null, {
52→      status: 303,
53→      headers: {
54→        Location: "/confirmed",
55→      },
56→    });
57→  } catch (error) {
58→    after(() => parseError(error));
59→    return NextResponse.json(
60→      { error: "An unexpected error occurred" },
61→      { status: 500 }
62→    );
63→  }
64→}
