22→export const searchUsers = async (
23→  query: string
24→): Promise<
25→  | {
26→      data: string[];
27→    }
28→  | {
29→      error: unknown;
30→    }
31→> => {
32→  try {
33→    const { orgId } = await auth();
34→
35→    if (!orgId) {
36→      throw new Error("Not logged in");
37→    }
38→
39→    const clerk = await clerkClient();
40→
41→    const members = await clerk.organizations.getOrganizationMembershipList({
42→      organizationId: orgId,
43→      limit: 100,
44→    });
45→
46→    const users = members.data.map((user) => ({
47→      id: user.id,
