 61→    quote: "You refuse to learn from vegetables; where are the robots?",
 62→  },
 63→  {
 64→    img: "/testimonials/cat_happy.png",
 65→    name: "Well ... you might just miss out on building",
 66→    title: "a fictional cat food shop then.",
 67→    quote: "You don't see the point of learning web development.",
 68→  },
 69→];
