207→  ux: ImpactItem[];
208→}
209→
210→function TelemetryDisplay({
211→  latency,
212→  aggregateImpact,
213→  enabledCaps,
214→}: {
215→  latency: number;
216→  aggregateImpact: AggregateImpact;
217→  enabledCaps: Set<SystemCapability>;
218→}) {
219→  const driftColor =
220→    aggregateImpact.latency < 0 ? "text-green-400" : "text-red-400 opacity-40";
221→  const driftPrefix = aggregateImpact.latency >= 0 ? "+" : "";
222→  const integrityColor = enabledCaps.has("persistence")
223→    ? "text-cyan-400"
224→    : "text-yellow-500/50";
225→  const integrityStatus = enabledCaps.has("persistence") ? "ACID" : "Volatile";
226→
227→  return (
228→    <div className="border-white/5 border-b p-6">
229→      <h2 className="mb-4 font-bold text-white/40 text-xs uppercase tracking-widest">
230→        Live Telemetry
231→      </h2>
232→      <div className="grid grid-cols-2 gap-4">
233→        <div className="rounded-xl border border-white/5 bg-white/5 p-4">
234→          <div className="mb-1 text-[10px] text-white/40 uppercase">
235→            Latency
236→          </div>
237→          <div className="font-mono text-white text-xl">{latency}ms</div>
238→          <div className={`mt-1 text-[10px] ${driftColor}`}>
239→            {driftPrefix}
240→            {aggregateImpact.latency}ms drift
241→          </div>
242→        </div>
243→        <div className="rounded-xl border border-white/5 bg-white/5 p-4">
244→          <div className="mb-1 text-[10px] text-white/40 uppercase">
245→            Integrity
246→          </div>
247→          <div className={`font-mono text-xl ${integrityColor}`}>
248→            {integrityStatus}
249→          </div>
250→        </div>
251→      </div>
252→    </div>
253→  );
254→}
255→
256→// --- Main Lab Component ---
257→
258→export default function ToggleLab() {
259→  const [mode, setMode] = useQueryState(
260→    "preset",
261→    parseAsString.withDefault("modern").withOptions({ history: "replace" })
262→  );
263→
264→  const [enabledCaps, setEnabledCaps] = useState<Set<SystemCapability>>(
265→    new Set()
266→  );
267→  const [isProcessing, setIsProcessing] = useState(false);
268→  const [showSuccess, setShowSuccess] = useState(false);
269→  const [latency, setLatency] = useState(INITIAL_LATENCY);
270→  const [activeStep, setActiveStep] = useState<SystemCapability | null>(null);
271→  const [terminalOutput, setTerminalOutput] = useState<
272→    { id: string; text: string }[]
273→  >([]);
274→
275→  useEffect(() => {
276→    const presets: Record<LabPreset, SystemCapability[]> = {
277→      minimal: [],
278→      modern: [
279→        "validation",
280→        "optimistic",
281→        "server_action",
282→        "persistence",
283→        "revalidation",
284→      ],
285→      fragile: ["persistence"],
286→      monolith: ["validation", "persistence"],
287→    };
288→    setEnabledCaps(new Set(presets[mode as LabPreset] || presets.modern));
289→  }, [mode]);
290→
291→  const aggregateImpact = useMemo<AggregateImpact>(
292→    () =>
293→      Array.from(enabledCaps).reduce(
294→        (acc, capId) => {
295→          const cap = CAPABILITIES.find((c) => c.id === capId);
296→          if (!cap) {
297→            return acc;
298→          }
299→          return {
300→            latency: acc.latency + cap.impact.latency,
301→            ux: [...acc.ux, { id: cap.id, label: cap.impact.ux }],
302→            dx: [...acc.dx, { id: cap.id, label: cap.impact.dx }],
303→          };
304→        },
305→        {
306→          latency: 0,
307→          ux: [],
308→          dx: [],
309→        } as AggregateImpact
310→      ),
311→    [enabledCaps]
312→  );
313→
314→  const toggleCap = (id: SystemCapability) => {
315→    setEnabledCaps((prev) => {
316→      const next = new Set(prev);
317→      if (next.has(id)) {
318→        next.delete(id);
319→      } else {
320→        next.add(id);
321→      }
322→      return next;
323→    });
324→    setMode(null);
325→  };
326→
327→  const addLog = (text: string) => {
328→    setTerminalOutput((prev) => [...prev, { id: crypto.randomUUID(), text }]);
329→  };
330→
331→  const handleClick = async () => {
332→    if (isProcessing) {
333→      return;
334→    }
335→
336→    setIsProcessing(true);
337→    setShowSuccess(false);
338→    setLatency(INITIAL_LATENCY);
339→    setTerminalOutput([
340→      { id: "start", text: "[system] starting request sequence..." },
341→    ]);
342→
343→    const sequence: SystemCapability[] = [
344→      "validation",
345→      "optimistic",
346→      "network",
347→      "server_action",
348→      "persistence",
349→      "revalidation",
350→    ];
351→
352→    let currentLatency = 0;
353→
354→    for (const stepId of sequence) {
355→      const isNetwork = stepId === "network";
356→      const isEnabled = enabledCaps.has(stepId as SystemCapability);
357→
358→      if (isNetwork || isEnabled) {
359→        setActiveStep(stepId as SystemCapability);
360→        const config = CAPABILITIES.find((c) => c.id === stepId);
361→        const baseLatency = config?.impact.latency || DEFAULT_STEP_LATENCY;
362→        const stepLatency = baseLatency + Math.random() * LATENCY_VARIANCE;
363→
364→        addLog(`[exec] ${stepId} in progress...`);
365→        await new Promise((r) => setTimeout(r, stepLatency));
366→
367→        currentLatency += stepLatency;
368→        setLatency(Math.floor(currentLatency));
369→      }
370→    }
371→
372→    setActiveStep(null);
373→    addLog("[system] sequence complete.");
374→    setShowSuccess(true);
375→    setIsProcessing(false);
376→  };
377→
378→  const buttonStateLabel = useMemo(() => {
379→    if (isProcessing) {
380→      return "Tracing...";
381→    }
382→    if (showSuccess) {
383→      return "Success";
384→    }
385→    return "Direct Action";
386→  }, [isProcessing, showSuccess]);
387→
388→  const buttonStateKey = useMemo(() => {
389→    if (isProcessing) {
390→      return "tracing";
391→    }
392→    if (showSuccess) {
393→      return "success";
394→    }
395→    return "idle";
396→  }, [isProcessing, showSuccess]);
397→
398→  return (
399→    <main className="relative flex min-h-screen flex-col bg-[#050505] font-sans text-white selection:bg-white/20">
400→      <div
401→        className="pointer-events-none absolute inset-0 text-white"
402→        style={{
403→          backgroundImage: "radial-gradient(#fff 1px, transparent 1px)",
404→          backgroundSize: "24px 24px",
405→          opacity: GRID_OPACITY,
406→        }}
407→      />
408→
409→      <header className="flex h-16 items-center justify-between border-white/5 border-b px-8 backdrop-blur-md">
410→        <div className="flex items-center gap-4">
411→          <div className="flex h-8 w-8 items-center justify-center rounded bg-white/10">
412→            <Zap className="h-4 w-4 text-yellow-400" />
413→          </div>
414→          <h1 className="font-bold text-lg tracking-tight">
415→            Toggle Lab{" "}
416→            <span className="ml-2 font-normal text-white/40">v1.1.0</span>
417→          </h1>
418→        </div>
419→        <div className="flex gap-4">
420→          {(["minimal", "modern", "fragile", "monolith"] as const).map((p) => (
421→            <Link
422→              className={`rounded-full border px-3 py-1.5 text-xs transition-all ${
423→                mode === p
424→                  ? "border-white bg-white text-black"
425→                  : "border-white/10 text-white/40 hover:border-white/20"
426→              }`}
427→              href={`?preset=${p}`}
428→              key={p}
429→            >
430→              {p.toUpperCase()}
431→            </Link>
432→          ))}
433→        </div>
434→      </header>
435→
436→      <div className="grid flex-1 grid-cols-12 overflow-hidden">
437→        <aside className="col-span-3 flex flex-col overflow-y-auto border-white/5 border-r bg-white/2 p-6">
438→          <h2 className="mb-4 font-bold text-white/40 text-xs uppercase tracking-widest">
439→            System Capabilities
440→          </h2>
441→          <div className="space-y-3">
442→            {CAPABILITIES.map((cap) => (
443→              <CapabilityButton
444→                cap={cap}
445→                isEnabled={enabledCaps.has(cap.id)}
446→                key={cap.id}
447→                onToggle={toggleCap}
448→              />
449→            ))}
450→          </div>
451→        </aside>
452→
453→        <section className="relative col-span-6 flex flex-col items-center justify-center p-12">
454→          <div
455→            className="pointer-events-none absolute inset-0 flex items-center justify-center"
456→            style={{ opacity: PIPELINE_BG_OPACITY }}
457→          >
458→            <div className="h-[600px] w-[600px] rounded-full border border-white/10" />
459→          </div>
460→
461→          <div className="relative z-10 flex w-full max-w-2xl flex-col items-center gap-16">
462→            <PipelineVisualization
463→              activeStep={activeStep}
464→              enabledCaps={enabledCaps}
465→            />
466→
467→            <Button
468→              className={`h-24 w-64 rounded-3xl font-bold text-2xl shadow-2xl transition-all duration-500 ${
469→                showSuccess
470→                  ? "bg-green-500 text-white shadow-[0_0_40px_rgba(34,197,94,0.3)] hover:bg-green-600"
471→                  : "bg-white text-black hover:scale-105 hover:shadow-[0_0_50px_rgba(255,255,255,0.2)] active:scale-95"
472→              } ${isProcessing ? "pointer-events-none opacity-30 blur-sm" : ""}`}
473→              disabled={isProcessing}
474→              onClick={handleClick}
475→              type="button"
476→            >
477→              <AnimatePresence mode="wait">
478→                <motion.span
479→                  animate={{ opacity: 1, y: 0 }}
480→                  exit={{ opacity: 0, y: -10 }}
481→                  initial={{ opacity: 0, y: 10 }}
482→                  key={buttonStateKey}
483→                >
484→                  {buttonStateLabel}
485→                </motion.span>
486→              </AnimatePresence>
487→            </Button>
488→          </div>
489→        </section>
490→
491→        <aside className="col-span-3 flex flex-col border-white/5 border-l bg-white/2">
492→          <TelemetryDisplay
493→            aggregateImpact={aggregateImpact}
494→            enabledCaps={enabledCaps}
495→            latency={latency}
496→          />
497→
498→          <div className="flex-1 overflow-y-auto p-6">
499→            <AnimatePresence mode="wait">
500→              {activeStep ? (
501→                <motion.div
502→                  animate={{ opacity: 1, x: 0 }}
503→                  className="space-y-6"
504→                  exit={{ opacity: 0, x: -20 }}
505→                  initial={{ opacity: 0, x: 20 }}
506→                  key={activeStep}
507→                >
508→                  <h2 className="font-bold text-white/40 text-xs uppercase tracking-widest">
509→                    Active Process
510→                  </h2>
511→                  <div className="rounded-xl border border-white/10 bg-white/5 p-4">
512→                    <div className="mb-2 font-mono text-cyan-400 text-xs">
513→                      [process] {activeStep.toUpperCase()}
514→                    </div>
515→                    <p className="text-white/60 text-xs leading-relaxed">
516→                      {
517→                        CAPABILITIES.find((c) => c.id === activeStep)
518→                          ?.description
