534→                  </div>
535→                </motion.div>
536→              ) : (
537→                <motion.div
538→                  animate={{ opacity: 1 }}
539→                  className="space-y-8"
540→                  initial={{ opacity: 0 }}
541→                  key="aggregate"
542→                >
543→                  <div>
544→                    <h2 className="mb-4 font-bold text-white/40 text-xs uppercase tracking-widest">
545→                      Aggregate Impact
