describe("checkEmailDeliverability", () => {
  test("returns valid when no API key configured", async () => {
    const result = await checkEmailDeliverability("test@obscure-domain.xyz", "");
    expect(result.valid).toBe(true);
  });

  test("returns valid for known good domains without calling API", async () => {
    const result = await checkEmailDeliverability("test@gmail.com", "fake-key");
    expect(result.valid).toBe(true);
  });
});
```

**Step 3: Run test to verify it fails**

Run: `cd apps/web && bun test lib/email-validation.test.ts`
Expected: FAIL — `checkEmailDeliverability` not exported

**Step 4: Add the deliverability check**

Update `apps/web/lib/email-validation.ts` to add:

```typescript
const TRUSTED_DOMAINS = new Set([
  "gmail.com", "googlemail.com", "outlook.com", "hotmail.com",
  "live.com", "yahoo.com", "icloud.com", "me.com", "mac.com",
  "protonmail.com", "proton.me", "fastmail.com", "hey.com",
  "aol.com", "zoho.com", "yandex.com", "mail.com",
]);

export async function checkEmailDeliverability(
  email: string,
  apiKey: string
): Promise<ValidationResult> {
  const domain = email.split("@")[1]?.toLowerCase();

  // Skip API check for well-known domains or when no key configured
  if (!apiKey || !domain || TRUSTED_DOMAINS.has(domain)) {
    return { valid: true };
  }

  try {
    const response = await fetch(
      `https://emailvalidation.abstractapi.com/v1/?api_key=${apiKey}&email=${encodeURIComponent(email)}`
    );

    if (!response.ok) {
      // Fail open — don't block signups if the API is down
      return { valid: true };
    }

    const data = await response.json();

    if (data.deliverability === "UNDELIVERABLE") {
      return { valid: false, reason: "undeliverable" };
    }

    return { valid: true };
  } catch {
    // Fail open on network errors
    return { valid: true };
  }
}
```

Update `validateEmail` to accept an optional `apiKey` parameter and call `checkEmailDeliverability` as Layer 2:

```typescript
export async function validateEmail(
  email: string,
  apiKey?: string
): Promise<ValidationResult> {
  if (!email || typeof email !== "string" || !email.includes("@")) {
    return { valid: false, reason: "invalid_format" };
  }

  if (isDisposableEmail(email)) {
    return { valid: false, reason: "disposable" };
  }

  if (apiKey) {
    return checkEmailDeliverability(email, apiKey);
  }

  return { valid: true };
}
```

