      <h1 className="mt-2 font-bold text-3xl tracking-tight">
        {digest.title}
      </h1>
      <p className="mt-2 text-lg text-muted-foreground italic">
        &ldquo;{digest.misconception}&rdquo;
      </p>
      {digest.sentAt && (
        <time className="mt-4 block text-muted-foreground text-sm">
          {new Date(digest.sentAt).toLocaleDateString("en-US", {
            year: "numeric",
            month: "long",
            day: "numeric",
          })}
        </time>
      )}
      <hr className="my-8" />
      <div className="prose dark:prose-invert max-w-none whitespace-pre-wrap">
        {digest.content}
      </div>
    </article>
  );
}
```

Note: The content rendering uses `whitespace-pre-wrap` for plain markdown. If rich markdown rendering is needed later, integrate the existing MDX components from `@repo/cms`.

