### Task 6: Create admin preview route

**Files:**
- Create: `apps/app/app/(authenticated)/digest/[id]/preview/page.tsx`

**Step 1: Create the preview page**

This page renders the React Email digest template server-side so Eric can see exactly what the email will look like.

```tsx
import { render } from "@react-email/components";
import { notFound } from "next/navigation";
import { database } from "@repo/database";
import { DigestEmail } from "@repo/email/templates/digest";
import { ObjectId } from "mongodb";

interface PreviewPageProps {
  params: Promise<{ id: string }>;
}

export default async function DigestPreviewPage({ params }: PreviewPageProps) {
  const { id } = await params;

  const digest = await database.digest.findOne({
    _id: new ObjectId(id),
  });

  if (!digest) {
    notFound();
  }

  const emailHtml = await render(
    DigestEmail({
      title: digest.title,
      misconception: digest.misconception,
      content: digest.content,
      series: digest.series,
    })
  );

  return (
    <div className="mx-auto max-w-4xl p-8">
      <div className="mb-4 flex items-center justify-between">
        <h1 className="font-bold text-xl">Email Preview</h1>
        <span className="rounded-full border px-3 py-1 text-muted-foreground text-xs">
          {digest.status}
        </span>
      </div>
      <div className="overflow-hidden rounded-lg border">
        <iframe
          srcDoc={emailHtml}
          title="Email preview"
          className="h-[800px] w-full"
          sandbox=""
        />
      </div>
    </div>
  );
}
```

Note: Check that `@react-email/components` exports `render`. If not, install `@react-email/render` separately. The `render` function converts a React Email component to HTML string.

